export function getPublishedTools() { return tools.filter((tool) => tool.status === "published"); }
export function getToolBySlug(slug: string) { return getPublishedTools().find((tool) => tool.slug === slug); }
export function getCategoryBySlug(slug: string) { return categories.find((category) => category.slug === slug); }
export function getToolsByCategory(slug: string) { return getPublishedTools().filter((tool) => tool.categorySlugs.includes(slug)); }
export function getCategoryNames(slugs: string[]) { return slugs.map((slug) => categories.find((category) => category.slug === slug)?.name || slug); }
